import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.B72_uj9U.js";const b=JSON.parse('{"title":"消费电子与代工行业专项模板","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/electronics/index.md","filePath":"zh/industry/electronics/index.md"}'),o={name:"zh/industry/electronics/index.md"};function n(h,t,i,l,s,c){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="消费电子与代工行业专项模板" tabindex="-1">消费电子与代工行业专项模板 <a class="header-anchor" href="#消费电子与代工行业专项模板" aria-label="Permalink to &quot;消费电子与代工行业专项模板&quot;">​</a></h1><blockquote><p><strong>行业背景：</strong> 消费电子供应链层级深、地域广，代工（OEM/ODM/EMS）模式普遍。主要风险：冲突矿产（3TG+钴）、数据安全与知识产权、劳工（大量劳务派遣）、环境（WEEE/RoHS）。关键参照：EICC（现RBA）行业准则、苹果/华为/三星供应商行为准则。</p></blockquote><h2 id="本节工具" tabindex="-1">本节工具 <a class="header-anchor" href="#本节工具" aria-label="Permalink to &quot;本节工具&quot;">​</a></h2><ul><li><a href="./saq.html">消费电子行业供应商自评问卷（SAQ-ELE）</a></li><li><a href="./audit-checklist.html">消费电子审核前文件请求清单</a></li></ul><hr><h2 id="行业风险优先级矩阵" tabindex="-1">行业风险优先级矩阵 <a class="header-anchor" href="#行业风险优先级矩阵" aria-label="Permalink to &quot;行业风险优先级矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>风险类别</th><th>风险等级</th><th>核心指标</th></tr></thead><tbody><tr><td>冲突矿产（3TG：锡/钽/钨/金 + 钴）</td><td>🔴 极高</td><td>CMRT/EMRT填报、冶炼厂溯源</td></tr><tr><td>数据安全与客户IP</td><td>🔴 极高</td><td>数据访问控制、员工保密协议</td></tr><tr><td>劳务派遣比例过高</td><td>🟠 高</td><td>派遣工比例、同工同酬</td></tr><tr><td>过度加班（旺季）</td><td>🟠 高</td><td>旺季工时记录</td></tr><tr><td>RoHS / WEEE 合规</td><td>🟠 高</td><td>有害物质检测、回收体系</td></tr><tr><td>供应商知识产权保护</td><td>🟠 高</td><td>NDA覆盖、访问控制</td></tr><tr><td>网络安全（供应链攻击）</td><td>🟠 高</td><td>软件更新管控、第三方访问</td></tr><tr><td>有害物质（焊接/喷涂）</td><td>🟡 中高</td><td>职业健康监测、个人防护</td></tr></tbody></table><hr><h2 id="关键法规参照" tabindex="-1">关键法规参照 <a class="header-anchor" href="#关键法规参照" aria-label="Permalink to &quot;关键法规参照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>法规 / 标准</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>RBA（责任商业联盟）行为准则</strong></td><td>电子行业主要客户要求（苹果、Dell、HP等）</td></tr><tr><td><strong>RoHS（有害物质限制指令）</strong></td><td>欧盟市场</td></tr><tr><td><strong>WEEE（废旧电子设备指令）</strong></td><td>欧盟回收义务</td></tr><tr><td><strong>冲突矿产（Dodd-Frank §1502）</strong></td><td>美国上市公司供应链披露</td></tr><tr><td><strong>IEC 62443</strong></td><td>工业控制系统安全</td></tr><tr><td><strong>ISO 27001</strong></td><td>信息安全管理</td></tr><tr><td><strong>《个人信息保护法》（中国）</strong></td><td>处理个人数据的供应商</td></tr><tr><td><strong>GDPR</strong></td><td>处理欧盟居民数据</td></tr></tbody></table><hr><h2 id="参考案例" tabindex="-1">参考案例 <a class="header-anchor" href="#参考案例" aria-label="Permalink to &quot;参考案例&quot;">​</a></h2><ul><li><a href="/zh/cases/csr/foxconn-apple.html">富士康/苹果：工人权益与品牌压力</a> — 劳工、审核局限</li><li><a href="/zh/cases/ip/ge-aviation.html">GE Aviation 涡轮叶片图纸窃密案</a> — 内部人员IP泄露</li><li><a href="/zh/cases/security/target-hvac.html">Target HVAC 供应商入侵案</a> — 第三方网络访问</li></ul>',13)])])}const g=d(o,[["render",n]]);export{b as __pageData,g as default};
